class Customer {
    private final CustomerId id;
    private final CustomerName name;
    private final List<Order> orders;

    Customer(CustomerId id, CustomerName name, List<Order> orders) {
        this.id = id;
        this.name = name;
        this.orders = Collections.unmodifiableList(orders);
    }

    Money calculateLifetimeValue() {
        return orders.stream()
            .map(Order::calculateTotal)
            .reduce(Money.ZERO, Money::add);
    }

    boolean isHighValueCustomer() {
        return calculateLifetimeValue().isGreaterThan(Money.of(1000));
    }
}
